import { useEffect, useState } from "react";
import { API } from "../api/base";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {

  const companyName =
    localStorage.getItem("username") || "Company";

  const token = localStorage.getItem("token");

  const [analytics, setAnalytics] = useState(null);

  /* =========================
     FETCH COMPANY ANALYTICS
  ========================= */
  useEffect(() => {
    const fetchAnalytics = async () => {
      try {
        const res = await fetch(`${API}/api/company/analytics`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        const data = await res.json();
        setAnalytics(data);
      } catch (err) {
        console.error("Analytics error:", err);
      }
    };

    fetchAnalytics();
  }, [token]);

  return (
    <div className="company-dashboard">

      <header className="company-header">
        <h1>{companyName}</h1>

        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {/* =========================
         ANALYTICS SECTION
      ========================= */}

      {analytics && (
        <div className="stats-row">

          <div className="stat-box">
            <h3>Total Bugs</h3>
            <p>{analytics.totalBugs}</p>
          </div>

          <div className="stat-box">
            <h3>Pending</h3>
            <p>{analytics.pendingBugs}</p>
          </div>

          <div className="stat-box">
            <h3>Approved</h3>
            <p>{analytics.approvedBugs}</p>
          </div>

          <div className="stat-box">
            <h3>Total Paid</h3>
            <p>₹{analytics.totalPaid}</p>
          </div>

          <div className="stat-box wallet">
            <h3>Wallet Balance</h3>
            <p>₹{analytics.walletBalance}</p>
          </div>

        </div>
      )}

      {/* =========================
         DASHBOARD CARDS
      ========================= */}

      <div className="dashboard-cards">
        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/pending")}
        >
          <h2>New Bugs</h2>
          <p>Review & take action</p>
        </div>

        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/history")}
        >
          <h2>Bug History</h2>
          <p>Approved, rejected & duplicate</p>
        </div>
      </div>

    </div>
  );
}
